def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 1:
            priorities[i] = ratio ** 4 + np.log1p(ratio)
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 6):
                term = (ratio ** j) / (j ** 2)
                if j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.8
                score += term
            if bin_capacity < item * 1.5:
                score *= 2
            elif bin_capacity < item * 3:
                score *= 1.3
            else:
                for k in range(1, 4):
                    score += (bin_capacity / (item * k)) ** 0.5 / (k + 1)
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 1
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 3
        elif priorities[i] < 0:
            priorities[i] = 0
    return priorities
